-- Populate geteducated_schools.wordpress_id from Tony Huffman 2025 Year-End
-- Degrees Report (CSV shared by Josh, 2026-05-04). 1697 unique schools.
--
-- Strategy: UPSERT on slug. Rows that already exist (matched by slug) get
-- their wordpress_id updated. Rows whose slug does not exist yet are
-- inserted fresh so the wordpress_id is still available at publish time
-- when convertLinksToShortcodes() does its slug lookup.
--
-- Source verification: Emporia State University = 3031 (matches Tony example).
-- Source verification: Southern New Hampshire University = 22742 (matches existing
-- WORDPRESS_CONTRIBUTOR_IDS reference in src/services/wordpressClient.js).

ON CONFLICT (slug) DO UPDATE SET
  wordpress_id = EXCLUDED.wordpress_id,
  updated_at = NOW();
